"""Unit tests for the JSONPath-to-JSON-Schema converter.

These tests verify the conversion logic in isolation -- no server or model
is required.
"""

import json
import unittest

from sglang.srt.constrained.json_path import (
    _parse_json_path,
    _segments_to_schema,
    json_path_to_json_schema,
    json_path_to_json_schema_str,
)


class TestParseJsonPath(unittest.TestCase):
    """Tests for the low-level JSONPath parser."""

    def test_root_only(self):
        segments = _parse_json_path("$")
        self.assertEqual(segments, [])

    def test_single_property(self):
        segments = _parse_json_path("$.name")
        self.assertEqual(segments, [("property", "name")])

    def test_nested_properties(self):
        segments = _parse_json_path("$.store.book")
        self.assertEqual(
            segments, [("property", "store"), ("property", "book")]
        )

    def test_array_wildcard(self):
        segments = _parse_json_path("$.items[*]")
        self.assertEqual(segments, [("property", "items"), ("array_wildcard",)])

    def test_array_index(self):
        segments = _parse_json_path("$.items[0]")
        self.assertEqual(segments, [("property", "items"), ("array_index", 0)])

    def test_bracket_notation(self):
        segments = _parse_json_path("$['store']['book']")
        self.assertEqual(
            segments, [("property", "store"), ("property", "book")]
        )

    def test_mixed_notation(self):
        segments = _parse_json_path("$.store['book'][*].author")
        self.assertEqual(
            segments,
            [
                ("property", "store"),
                ("property", "book"),
                ("array_wildcard",),
                ("property", "author"),
            ],
        )

    def test_complex_path(self):
        segments = _parse_json_path("$.store.book[*].author")
        self.assertEqual(
            segments,
            [
                ("property", "store"),
                ("property", "book"),
                ("array_wildcard",),
                ("property", "author"),
            ],
        )

    def test_array_index_large(self):
        segments = _parse_json_path("$.data[42].value")
        self.assertEqual(
            segments,
            [("property", "data"), ("array_index", 42), ("property", "value")],
        )


class TestParseJsonPathErrors(unittest.TestCase):
    """Tests for error handling in the JSONPath parser."""

    def test_empty_string(self):
        with self.assertRaises(ValueError) as ctx:
            _parse_json_path("")
        self.assertIn("non-empty string", str(ctx.exception))

    def test_none_input(self):
        with self.assertRaises(ValueError):
            _parse_json_path(None)

    def test_missing_root(self):
        with self.assertRaises(ValueError) as ctx:
            _parse_json_path("name")
        self.assertIn("must start with '$'", str(ctx.exception))

    def test_recursive_descent(self):
        with self.assertRaises(ValueError) as ctx:
            _parse_json_path("$..author")
        self.assertIn("Recursive descent", str(ctx.exception))

    def test_filter_expression(self):
        with self.assertRaises(ValueError) as ctx:
            _parse_json_path("$.items[?(@.price<10)]")
        self.assertIn("Filter expressions", str(ctx.exception))

    def test_current_node_reference(self):
        with self.assertRaises(ValueError) as ctx:
            _parse_json_path("$.items[?(@.active)]")
        self.assertIn("Current-node references", str(ctx.exception))


class TestSegmentsToSchema(unittest.TestCase):
    """Tests for schema generation from parsed segments."""

    def test_empty_segments(self):
        schema = _segments_to_schema([])
        self.assertEqual(schema, {})

    def test_single_property(self):
        schema = _segments_to_schema([("property", "name")])
        self.assertEqual(
            schema,
            {
                "type": "object",
                "required": ["name"],
                "properties": {"name": {}},
            },
        )

    def test_nested_properties(self):
        schema = _segments_to_schema(
            [("property", "a"), ("property", "b")]
        )
        self.assertEqual(
            schema,
            {
                "type": "object",
                "required": ["a"],
                "properties": {
                    "a": {
                        "type": "object",
                        "required": ["b"],
                        "properties": {"b": {}},
                    }
                },
            },
        )

    def test_array_wildcard(self):
        schema = _segments_to_schema(
            [("property", "items"), ("array_wildcard",)]
        )
        self.assertEqual(
            schema,
            {
                "type": "object",
                "required": ["items"],
                "properties": {
                    "items": {"type": "array", "items": {}}
                },
            },
        )

    def test_array_index(self):
        # Array index is treated the same as wildcard for schema purposes
        schema = _segments_to_schema(
            [("property", "items"), ("array_index", 0)]
        )
        self.assertEqual(
            schema,
            {
                "type": "object",
                "required": ["items"],
                "properties": {
                    "items": {"type": "array", "items": {}}
                },
            },
        )


class TestJsonPathToJsonSchema(unittest.TestCase):
    """End-to-end tests for the JSONPath-to-JSON-Schema conversion."""

    def test_root_only(self):
        schema = json_path_to_json_schema("$")
        self.assertEqual(schema, {})

    def test_single_property(self):
        schema = json_path_to_json_schema("$.name")
        expected = {
            "type": "object",
            "required": ["name"],
            "properties": {"name": {}},
        }
        self.assertEqual(schema, expected)

    def test_nested_properties(self):
        schema = json_path_to_json_schema("$.store.book")
        expected = {
            "type": "object",
            "required": ["store"],
            "properties": {
                "store": {
                    "type": "object",
                    "required": ["book"],
                    "properties": {"book": {}},
                }
            },
        }
        self.assertEqual(schema, expected)

    def test_full_path_with_array(self):
        schema = json_path_to_json_schema("$.store.book[*].author")
        expected = {
            "type": "object",
            "required": ["store"],
            "properties": {
                "store": {
                    "type": "object",
                    "required": ["book"],
                    "properties": {
                        "book": {
                            "type": "array",
                            "items": {
                                "type": "object",
                                "required": ["author"],
                                "properties": {"author": {}},
                            },
                        }
                    },
                }
            },
        }
        self.assertEqual(schema, expected)

    def test_bracket_notation_equivalent(self):
        """Bracket notation should produce the same result as dot notation."""
        dot_schema = json_path_to_json_schema("$.store.book")
        bracket_schema = json_path_to_json_schema("$['store']['book']")
        self.assertEqual(dot_schema, bracket_schema)

    def test_array_index_same_as_wildcard(self):
        """Array index should produce the same schema as wildcard."""
        wildcard_schema = json_path_to_json_schema("$.items[*].id")
        index_schema = json_path_to_json_schema("$.items[0].id")
        self.assertEqual(wildcard_schema, index_schema)

    def test_deep_nesting(self):
        schema = json_path_to_json_schema("$.a.b.c.d.e")
        # Verify the outer layer
        self.assertEqual(schema["type"], "object")
        self.assertEqual(schema["required"], ["a"])
        # Verify the innermost layer
        inner = schema["properties"]["a"]["properties"]["b"]["properties"]["c"]["properties"]["d"]
        self.assertEqual(
            inner,
            {
                "type": "object",
                "required": ["e"],
                "properties": {"e": {}},
            },
        )

    def test_multiple_arrays(self):
        schema = json_path_to_json_schema("$.data[*].items[*].value")
        expected = {
            "type": "object",
            "required": ["data"],
            "properties": {
                "data": {
                    "type": "array",
                    "items": {
                        "type": "object",
                        "required": ["items"],
                        "properties": {
                            "items": {
                                "type": "array",
                                "items": {
                                    "type": "object",
                                    "required": ["value"],
                                    "properties": {"value": {}},
                                },
                            }
                        },
                    },
                }
            },
        }
        self.assertEqual(schema, expected)


class TestJsonPathToJsonSchemaStr(unittest.TestCase):
    """Tests for the string output variant."""

    def test_returns_valid_json(self):
        result = json_path_to_json_schema_str("$.store.book[*].author")
        parsed = json.loads(result)
        self.assertIsInstance(parsed, dict)
        self.assertEqual(parsed["type"], "object")

    def test_compact_format(self):
        result = json_path_to_json_schema_str("$.name")
        # Compact JSON should not have spaces after separators
        self.assertNotIn(": ", result)
        self.assertNotIn(", ", result)

    def test_root_returns_empty_object(self):
        result = json_path_to_json_schema_str("$")
        self.assertEqual(json.loads(result), {})


class TestJsonPathValidation(unittest.TestCase):
    """Tests for validation and edge cases."""

    def test_whitespace_trimmed(self):
        schema = json_path_to_json_schema("  $.name  ")
        expected = json_path_to_json_schema("$.name")
        self.assertEqual(schema, expected)

    def test_unsupported_recursive_descent(self):
        with self.assertRaises(ValueError):
            json_path_to_json_schema("$..name")

    def test_unsupported_filter(self):
        with self.assertRaises(ValueError):
            json_path_to_json_schema("$.items[?(@.price<10)]")

    def test_unsupported_current_node(self):
        with self.assertRaises(ValueError):
            json_path_to_json_schema("$.items[?(@.active)]")

    def test_invalid_empty(self):
        with self.assertRaises(ValueError):
            json_path_to_json_schema("")

    def test_invalid_no_root(self):
        with self.assertRaises(ValueError):
            json_path_to_json_schema("store.book")


if __name__ == "__main__":
    unittest.main()

